// S3 lifecycle rule: HIPAA 6-year retention
{
  "Rules": [{
    "ID": "hipaa-trace-retention",
    "Status": "Enabled",
    "Filter": {"Prefix": "traces/hipaa/"},
    "Transitions": [
      {"Days": 90, "StorageClass": "STANDARD_IA"},
      {"Days": 365, "StorageClass": "GLACIER"}
    ],
    "Expiration": {"Days": 2192}  // 6 years
  }]
}
